// 1 ➜ Cargar datos de ambos nodos Google Sheets
const datosMeses = $items("Get row(s) in sheet").map(i => i.json);   // Hoja 1
const productos  = $items("Get row(s) in sheet1").map(i => i.json);  // Hoja 2

// 2 ➜ Mes actual (o forzado para pruebas)
const forzarMes = "";  // pon "" para mes real
const fecha     = new Date();
const nombreMes = forzarMes || fecha.toLocaleString("es-ES", { month: "long" });
const mesActual = nombreMes.charAt(0).toUpperCase() + nombreMes.slice(1);

// 3 ➜ Buscar planificación
const entradaMes = datosMeses.find(r =>
  (r.MESES || "").toLowerCase() === mesActual.toLowerCase()
);
const seccionPrincipal = entradaMes?.CONTENIDO || "Mujer y Teen";
const mesEspecial      = entradaMes?.["MES ESPECIAL"] || "";

// 4 ➜ Propagar sección hacia abajo (col_1 vacía)
let ultimaSeccion = "";
for (const fila of productos) {
  if (fila.col_1 && fila.col_1.trim() !== "") {
    ultimaSeccion = fila.col_1.trim();
  } else {
    fila.col_1 = ultimaSeccion;
  }
}

// 5 ➜ Crear lista de secciones: primero la del mes, luego otras
const seccionesOrdenadas = [
  seccionPrincipal,
  ...datosMeses
    .map(r => r.CONTENIDO)
    .filter(s => s && s !== seccionPrincipal)
];

// 6 ➜ Buscar una fila libre en esas secciones
let fila = null;
let seccionElegida = "";
for (const seccion of seccionesOrdenadas) {
  const candidatos = productos
    .filter(r => (r.col_1 || "").toLowerCase() === seccion.toLowerCase())
    .filter(r => (r.USADO || "").toUpperCase() !== "SI");

  if (candidatos.length > 0) {
    fila = candidatos[Math.floor(Math.random() * candidatos.length)];
    seccionElegida = seccion;
    break;
  }
}

// 7 ➜ Si no hay productos libres
if (!fila) {
  return [{
    json: { error: `No hay productos sin usar en ninguna sección.` }
  }];
}

// 8 ➜ Construir selección de productos
const CATS = [
  "BIKINI","TRIKINI","BAÑADOR","CULETÍN",
  "BÓXER","COMPLEMENTOS","CONJUNTOS"
];
const productosSeleccionados = {};
for (const cat of CATS) {
  if (fila[cat]) productosSeleccionados[cat] = fila[cat];
}

// 9 ➜ Salida
return [{
  json: {
    mes       : mesActual,
    seccion   : seccionElegida,
    especial  : mesEspecial,
    productos : productosSeleccionados,
    row_number: fila.row_number,
    USADO     : "SI"
  }
}];

