for (const tipo in productos) {
  const nombreProducto = productos[tipo];
  const nombreBusqueda = `${seccion.toUpperCase()} - ${nombreProducto}`;
  resultados.push({
    tipo,
    nombreProducto,
    nombreBusqueda
  });
}

return resultados;

const itemsOut = [];
let asunto = "";
let texto = "";
const imagenes = [];

// Extraer texto generado por el modelo y convertirlo en JSON válido
for (const item of items) {
  if (item.json.message?.content) {
    try {
      const respuesta = JSON.parse(item.json.message.content);
      asunto = respuesta.asunto || "Newsletter Munsuri";
      texto = respuesta.contenido || "";
    } catch (e) {
      // En caso de que no sea un JSON válido, usa como texto directamente
      asunto = "Newsletter Munsuri";
      texto = item.json.message.content || "";
    }
  } else if (item.json.id) {
    const id = item.json.id;
    const url = `https://drive.google.com/uc?export=view&id=${id}`;
    imagenes.push(url);
  }
}

// Asegurar que texto sea un string
texto = String(texto || "");

// Construir el HTML final
const imagenesHtml = imagenes.map(url => 
  `<img src="${url}" width="300" style="margin: 10px 10px 20px 0; border-radius: 8px;" />`
).join("\n");

const html = `
  <div style="font-family: Arial, sans-serif; line-height: 1.5;">
    <p>${texto.replace(/\n/g, "<br>")}</p>
    <p style="font-size: 10px; color: #777; margin-top: 30px;">
      Si ya no deseas recibir nuestra newsletter, puedes 
      <a href="https://munsuri.us16.list-manage.com/unsubscribe?u=5b89f35aa7397f201273afe99&id=a9f60d4085" target="_blank" style="color: #777;">
        cancelar tu suscripción aquí
      </a>.
    </p>
    <hr style="margin: 20px 0;">
    ${imagenesHtml}
  </div>
`;

itemsOut.push({ json: { asunto, html } });
return itemsOut;

